1	import { NextRequest, NextResponse } from "next/server";
2	import { store } from "@/lib/store";
3	
4	export async function GET(req: NextRequest) {
5	  const date = req.nextUrl.searchParams.get("date");
6	  const review = store.dailyReviews.find(
7	    (r: any) => r.userId === "demo" && r.date === date
8	  );
9	  return NextResponse.json(review || null);
10	}
11	
12	export async function POST(req: NextRequest) {
13	  const body = await req.json();
14	  const existing = store.dailyReviews.findIndex(
15	    (r: any) => r.userId === "demo" && r.date === body.date
16	  );
17	
18	  const review = {
19	    id: crypto.randomUUID(),
20	    userId: "demo",
21	    ...body,
22	    aiFeedback: body.aiFeedback || null,
23	    createdAt: new Date().toISOString(),
24	  };
25	
26	  if (existing !== -1) {
27	    store.dailyReviews[existing] = { ...store.dailyReviews[existing], ...review };
28	  } else {
29	    store.dailyReviews.push(review);
30	  }
31	
32	  return NextResponse.json(review);
33	}
