1	import { useState, useEffect } from "react";
2	import { View, Text } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, formatDate, getDomains } from "../../lib";
5	import "./index.scss";
6	
7	interface Habit {
8	  id: string;
9	  title: string;
10	  description: string | null;
11	  domainId: string;
12	  unit: string;
13	  targetValue: number;
14	  isActive: boolean;
15	  logs?: { date: string; completed: boolean; value: number }[];
16	}
17	
18	export default function IndexPage() {
19	  const [habits, setHabits] = useState<Habit[]>([]);
20	  const [loading, setLoading] = useState(true);
21	
22	  useDidShow(() => {
23	    fetchHabits();
24	  });
25	
26	  async function fetchHabits() {
27	    try {
28	      const data = await apiFetch("/api/habits?date=" + getToday());
29	      setHabits(data);
30	    } catch {
31	      Taro.showToast({ title: "获取今日习惯失败", icon: "none" });
32	    }
33	    setLoading(false);
34	  }
35	
36	  async function toggleHabit(habitId: string) {
37	    try {
38	      await apiFetch("/api/logs", {
39	        method: "POST",
40	        body: JSON.stringify({ habitId, date: getToday() }),
41	      });
42	      fetchHabits();
43	    } catch {
44	      Taro.showToast({ title: "打卡失败", icon: "none" });
45	    }
46	  }
47	
48	  const completedCount = habits.filter(
49	    (h) => h.logs?.length && h.logs[0]?.completed
50	  ).length;
51	  const totalCount = habits.filter((h) => h.isActive).length;
52	  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
53	
54	  return (
55	    <View className="page">
56	      <Text className="header-date">{formatDate(new Date())}</Text>
57	      <Text className="header-title">今日日课</Text>
58	
59	      <View className="progress-card">
60	        <View className="progress-ring">
61	          <View style={{
62	            width: "140rpx", height: "140rpx", borderRadius: "50%",
63	            background: `conic-gradient(#c4843e ${progressPct * 3.6}deg, #332e28 0deg)`,
64	            display: "flex", alignItems: "center", justifyContent: "center"
65	          }}>
66	            <View style={{
67	              width: "110rpx", height: "110rpx", borderRadius: "50%",
68	              background: "#221e1a", display: "flex", alignItems: "center", justifyContent: "center"
69	            }}>
70	              <Text className="progress-pct">{progressPct}%</Text>
71	            </View>
72	          </View>
73	        </View>
74	        <View className="progress-info">
75	          <Text className="progress-num">{completedCount}/{totalCount}</Text>
76	          <Text className="progress-label">今日已完成</Text>
77	        </View>
78	      </View>
79	
80	      {getDomains().map((domain) => {
81	        const domainHabits = habits.filter((h) => h.domainId === domain.name && h.isActive);
82	        if (domainHabits.length === 0) return null;
83	        return (
84	          <View key={domain.name}>
85	            <Text className="domain-title">{domain.icon} {domain.name}</Text>
86	            {domainHabits.map((habit) => {
87	              const done = !!(habit.logs?.length && habit.logs[0]?.completed);
88	              return (
89	                <View
90	                  key={habit.id}
91	                  className={`habit-item ${done ? "done" : ""}`}
92	                  onClick={() => toggleHabit(habit.id)}
93	                >
94	                  <View className={`check-icon ${done ? "checked" : ""}`}>
95	                    {done && <Text>✓</Text>}
96	                  </View>
97	                  <View className="habit-text">
98	                    <Text className={`habit-name ${done ? "done" : ""}`}>{habit.title}</Text>
99	                    {habit.description && <Text className="habit-desc">{habit.description}</Text>}
100	                  </View>
101	                  <Text className="habit-unit">{habit.targetValue}{habit.unit}</Text>
102	                </View>
103	              );
104	            })}
105	          </View>
106	        );
107	      })}
108	
109	      {totalCount === 0 && (
110	        <View className="empty">
111	          <Text>还没有习惯</Text>
112	          <Text>去「习惯」页面添加吧</Text>
113	        </View>
114	      )}
115	    </View>
116	  );
117	}
