7	export default function ReviewPage() {
8	  const [form, setForm] = useState({ score: 3, summary: "", highlight: "", lowlight: "" });
9	  const [submitted, setSubmitted] = useState(false);
10	  const [aiFeedback, setAiFeedback] = useState("");
11	  const [review, setReview] = useState<any>(null);
12	
13	  useDidShow(() => {
14	    apiFetch(`/api/review?date=${getToday()}`).then((data) => {
15	      if (data?.id) {
16	        setReview(data);
17	        setForm({ score: data.score, summary: data.summary || "", highlight: data.highlight || "", lowlight: data.lowlight || "" });
18	        setAiFeedback(data.aiFeedback || "");
19	        setSubmitted(true);
20	      }
21	    }).catch(() => {
22	      Taro.showToast({ title: "获取复盘数据失败", icon: "none" });
23	    });
24	  });
25	
26	  async function handleSubmit() {
27	    const data = await apiFetch("/api/review", {
28	      method: "POST",
29	      body: JSON.stringify({ ...form, date: getToday() }),
30	    });
31	    setSubmitted(true);
32	    setReview(data);
33	    try {
34	      const ai = await apiFetch("/api/insights", {
35	        method: "POST",
36	        body: JSON.stringify({ type: "review", data: form }),
37	      });
38	      setAiFeedback(ai.text || "");
39	    } catch {}
40	  }
41	
42	  if (review && submitted) {
43	    return (
44	      <View className="page">
45	        <Text className="page-title">每日复盘</Text>
46	        <View className="review-card center">
47	          <Text className="review-score">
48	            {["", "😔", "😐", "🙂", "😊", "🌟"][review.score]}
49	          </Text>
50	          <Text className="review-summary">今日评分 {review.score}/5</Text>
51	          <Text className="review-summary">{review.summary}</Text>
52	        </View>
53	
54	        {aiFeedback ? (
55	          <View className="ai-card">
56	            <Text className="ai-title">⭐ AI 教练点评</Text>
57	            <Text className="ai-text">{aiFeedback}</Text>
58	          </View>
59	        ) : null}
60	
61	        <View className="split-cards">
62	          <View className="split-card">
63	            <Text className="split-label">今日亮点</Text>
64	            <Text className="split-text">{review.highlight || "—"}</Text>
65	          </View>
66	          <View className="split-card">
67	            <Text className="split-label">待改进</Text>
68	            <Text className="split-text">{review.lowlight || "—"}</Text>
69	          </View>
70	        </View>
71	        <View className="submit-btn" onClick={() => setSubmitted(false)}>
72	          <Text>编辑复盘</Text>
73	        </View>
74	      </View>
75	    );
76	  }
77	
78	  return (
79	    <View className="page">
80	      <Text className="page-title">每日复盘</Text>
81	      <Text className="page-subtitle">三省吾身，日日精进</Text>
82	
83	      <View className="review-card">
84	        <View className="form-group">
85	          <Text className="form-label">今日整体评分</Text>
86	          <View className="stars">
87	            {[1, 2, 3, 4, 5].map((s) => (
88	              <Text key={s} className={`star ${form.score >= s ? "active" : ""}`} onClick={() => setForm({ ...form, score: s })}>⭐</Text>
89	            ))}
90	          </View>
91	        </View>
92	
93	        <View className="form-group">
94	          <Text className="form-label">一句话总结</Text>
95	          <Input className="form-input" placeholder="今天过得怎么样？" value={form.summary} onInput={(e) => setForm({ ...form, summary: e.detail.value })} />
96	        </View>
97	
98	        <View className="form-group">
99	          <Text className="form-label">今日亮点</Text>
100	          <Textarea className="form-textarea" placeholder="最值得骄傲的事" value={form.highlight} onInput={(e) => setForm({ ...form, highlight: e.detail.value })} maxlength={500} />
101	        </View>
102	
103	        <View className="form-group">
104	          <Text className="form-label">需要改进</Text>
105	          <Textarea className="form-textarea" placeholder="可以做得更好的地方" value={form.lowlight} onInput={(e) => setForm({ ...form, lowlight: e.detail.value })} maxlength={500} />
106	        </View>
107	
108	        <View className="submit-btn" onClick={handleSubmit}><Text>提交复盘</Text></View>
109	      </View>
110	    </View>
111	  );
112	}
