1	import Anthropic from "@anthropic-ai/sdk";
2	
3	const anthropic = new Anthropic({
4	  apiKey: process.env.CLAUDE_API_KEY || process.env.ANTHROPIC_API_KEY,
5	});
6	
7	export async function getAIRecommendation(prompt: string): Promise<string> {
8	  const msg = await anthropic.messages.create({
9	    model: "claude-sonnet-4-6",
10	    max_tokens: 1024,
11	    system:
12	      "你是一位专业的个人成长教练。回复简洁有力，风格如帝王侍读。每段不超过3句话。",
13	    messages: [{ role: "user", content: prompt }],
14	  });
15	  const block = msg.content[0];
16	  if (block.type === "text") return block.text;
17	  return "";
18	}
