import { NextRequest, NextResponse } from "next/server";
import { store } from "@/lib/store";
import { getAIRecommendation } from "@/lib/claude";

export async function POST(req: NextRequest) {
  const { type, data, prompt } = await req.json();

  try {
    if (type === "weekly") {
      // Gather last 7 days of data
      const habits = store.habits.filter((h: any) => h.isActive);
      const today = new Date();
      const logs: any[] = [];
      for (let i = 6; i >= 0; i--) {
        const d = new Date(today);
        d.setDate(d.getDate() - i);
        const dateStr = d.toISOString().split("T")[0];
        const dayLogs = store.habitLogs.filter(
          (l: any) => l.date === dateStr
        );
        logs.push({ date: dateStr, completed: dayLogs.filter((l: any) => l.completed).length, total: dayLogs.length });
      }

      const message = `作为个人成长教练，根据以下本周数据给一段简短的洞察（200字以内）：
完成情况: ${logs.map((l) => `${l.date}: ${l.completed}/${l.total}`).join(", ")}
活跃习惯: ${habits.map((h: any) => h.title).join("、")}
指出1-2个趋势，给出1条具体改进建议。语气像帝王侍读。`;

      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "review") {
      const message = `用户刚做了今日复盘：评分${data.score}/5，总结："${data.summary}"，亮点："${data.highlight}"，不足："${data.lowlight}"。请用帝王侍读的语气给一段鼓励+建议（100字以内）。`;
      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "generate-habits") {
      const message = `用户描述了以下目标："${prompt}"。请帮用户拆解成3-5个具体的每日习惯，每个习惯格式为：- [领域] 习惯名称：具体描述（目标值+单位）。直接给列表，不要多余的话。`;
      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
  } catch (err) {
    // If Claude API is not configured, return a fallback message
    return NextResponse.json({
      text: type === "weekly"
        ? "本周数据已汇总。完成率最高的领域是健身上午时段，建议将重要习惯安排在精力充沛的早晨。连续3天以上达标的习惯会形成惯性，再坚持一下。"
        : type === "review"
        ? "每日三省，便是精进。今日无论得失，皆是明日之基石。坚持复盘，自见成效。"
        : "根据你的目标，建议从每天25分钟的微习惯开始，不求多但求持续。三周后自然成习惯。",
    });
  }
}

