import { NextRequest, NextResponse } from "next/server";
import { store } from "@/lib/store";
import { getAIRecommendation } from "@/lib/claude";

const todayStr = () => new Date().toISOString().split("T")[0];

function getRecentLogs(daysBack: number) {
  const logs: { date: string; completed: number; total: number }[] = [];
  const today = new Date();
  for (let i = daysBack - 1; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().split("T")[0];
    const dayLogs = store.habitLogs.filter((l: any) => l.date === dateStr);
    logs.push({
      date: dateStr,
      completed: dayLogs.filter((l: any) => l.completed).length,
      total: dayLogs.length,
    });
  }
  return logs;
}

function getHabitCompletionRates(daysBack: number) {
  const habits = store.habits.filter((h: any) => h.isActive);
  const today = new Date();
  return habits.map((h: any) => {
    let completedDays = 0;
    let totalDays = 0;
    let lastCompleted = "";
    for (let i = daysBack - 1; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(d.getDate() - i);
      const dateStr = d.toISOString().split("T")[0];
      const log = store.habitLogs.find(
        (l: any) => l.habitId === h.id && l.date === dateStr
      );
      if (log) {
        totalDays++;
        if (log.completed) {
          completedDays++;
          lastCompleted = dateStr;
        }
      }
    }
    const consecutiveMiss =
      lastCompleted
        ? Math.floor(
            (Date.now() - new Date(lastCompleted).getTime()) /
              (1000 * 60 * 60 * 24)
          ) - 1
        : daysBack;
    return {
      title: h.title,
      domainId: h.domainId,
      rate: totalDays > 0 ? Math.round((completedDays / totalDays) * 100) : 0,
      consecutiveMiss: Math.max(0, consecutiveMiss),
    };
  });
}

function getTodayLogs() {
  const today = todayStr();
  return store.habitLogs.filter((l: any) => l.date === today);
}

function getStreak() {
  let streak = 0;
  const d = new Date();
  while (true) {
    const dateStr = d.toISOString().split("T")[0];
    const logs = store.habitLogs.filter((l: any) => l.date === dateStr);
    if (logs.length === 0 || logs.every((l: any) => !l.completed)) break;
    streak++;
    d.setDate(d.getDate() - 1);
  }
  return streak;
}

function getYesterdayReview() {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  const dateStr = d.toISOString().split("T")[0];
  return store.dailyReviews.find((r: any) => r.userId === "demo" && r.date === dateStr) || null;
}

function getProfile() {
  return store.profiles.get("demo") || null;
}

// Simple in-memory cache for daily goals
const goalCache: { date: string; goals: any[] } | null = null;
let _goalCache: { date: string; goals: any[] } | null = null;
let _goalCacheDate = "";

export async function POST(req: NextRequest) {
  const { type, data, prompt } = await req.json();

  try {
    if (type === "weekly") {
      const habits = store.habits.filter((h: any) => h.isActive);
      const logs = getRecentLogs(7);

      const message = `作为个人成长教练，根据以下本周数据给一段简短的洞察（200字以内）：
完成情况: ${logs.map((l) => `${l.date}: ${l.completed}/${l.total}`).join(", ")}
活跃习惯: ${habits.map((h: any) => h.title).join("、")}
指出1-2个趋势，给出1条具体改进建议。语气像帝王侍读。`;

      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "review") {
      const message = `用户刚做了今日复盘：评分${data.score}/5，总结："${data.summary}"，亮点："${data.highlight}"，不足："${data.lowlight}"。请用帝王侍读的语气给一段鼓励+建议（100字以内）。`;
      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "generate-habits") {
      const message = `用户描述了以下目标："${prompt}"。请帮用户拆解成3-5个具体的每日习惯，每个习惯格式为：- [领域] 习惯名称：具体描述（目标值+单位）。直接给列表，不要多余的话。`;
      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    // ---- Feature 1: AI 今日小结 (daily-summary) ----
    if (type === "daily-summary") {
      const logs = getTodayLogs();
      const activeHabits = store.habits.filter((h: any) => h.isActive);
      const totalActive = activeHabits.length;
      const completedCount = logs.filter((l: any) => l.completed).length;
      const streak = getStreak();
      const recentLogs = getRecentLogs(7);
      const yesterdayReview = getYesterdayReview();
      const profile = getProfile();

      // Fallback if no data yet today
      if (totalActive === 0) {
        return NextResponse.json({
          text: "今日尚未打卡，完成日课后自动生成小结。",
        });
      }

      const habitsTrend = activeHabits.map((h: any) => {
        const habitLogs = recentLogs.map((r) => {
          const log = store.habitLogs.find(
            (l: any) => l.habitId === h.id && l.date === r.date
          );
          return log ? log.completed : false;
        });
        return `${h.title}: [${habitLogs.map((c) => (c ? "✓" : "✗")).join(", ")}]`;
      }).join("\n");

      const message = `作为天子日课（个人成长系统）的帝王侍读，根据今日数据给一段精炼的日课小结（150字以内）。

今日完成：${completedCount}/${totalActive}
连续精进天数：${streak} 天

各习惯近7日趋势：
${habitsTrend}

${
  yesterdayReview
    ? `昨日复盘：
评分：${yesterdayReview.score}/5
总结：${yesterdayReview.summary || "未填写"}
亮点：${yesterdayReview.highlight || "未填写"}
不足：${yesterdayReview.lowlight || "未填写"}`
    : "昨日无复盘记录。"
}

${
  profile?.goals?.length
    ? `用户长期目标：${profile.goals.join("、")}`
    : ""
}
${profile?.wakeTime ? `作息：${profile.wakeTime}起床，${profile.sleepTime || "未设"}入睡` : ""}

语气应如帝王侍读向天子奏报——庄重而不失温度，肯定精进之处，点明可提升之处。`;

      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    // ---- Feature 2: AI 明日目标推荐 (daily-goals) ----
    if (type === "daily-goals") {
      // Check cache for today
      const td = todayStr();
      if (_goalCacheDate === td && _goalCache) {
        return NextResponse.json({ goals: _goalCache });
      }

      const rates = getHabitCompletionRates(14);
      const yesterdayReview = getYesterdayReview();
      const profile = getProfile();

      const message = `作为天子日课（个人成长系统）的帝王侍读，分析用户近14日数据，推荐1-3个今日最应关注的目标。

各习惯完成率及断档天数：
${rates
  .map(
    (r) =>
      `${r.title}（${r.domainId}）：完成率${r.rate}%，连续${r.consecutiveMiss > 0 ? `${r.consecutiveMiss}天未完成` : "坚持中"}`
  )
  .join("\n")}

${yesterdayReview ? `昨日复盘：评分${yesterdayReview.score}/5，总结"${yesterdayReview.summary || ""}"，亮点"${yesterdayReview.highlight || ""}"，不足"${yesterdayReview.lowlight || ""}"` : "昨日无复盘"}

${profile?.goals?.length ? `长期目标：${profile.goals.join("、")}` : ""}
${profile?.wakeTime ? `作息：${profile.wakeTime}起床` : ""}

请以JSON格式返回推荐目标数组，每个目标包含：
- title: 简短的标题（如"晨跑恢复"）
- detail: 具体建议内容（60字以内）
- reason: 推荐理由（40字以内）

格式要求：只返回一个合法的JSON对象，格式为 {"goals": [{"title": "...", "detail": "...", "reason": "..."}]}，不要其他任何文字。`;

      const raw = await getAIRecommendation(message);
      let goals: any[] = [];
      try {
        // Extract JSON from response (handle potential markdown wrapping)
        const jsonMatch = raw.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          const parsed = JSON.parse(jsonMatch[0]);
          goals = parsed.goals || [];
        }
      } catch {
        goals = [];
      }

      // Cache
      _goalCacheDate = td;
      _goalCache = goals;

      return NextResponse.json({ goals });
    }

    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
  } catch (err) {
    const fallbacks: Record<string, string> = {
      weekly:
        "本周数据已汇总。完成率最高的领域是健身上午时段，建议将重要习惯安排在精力充沛的早晨。连续3天以上达标的习惯会形成惯性，再坚持一下。",
      review:
        "每日三省，便是精进。今日无论得失，皆是明日之基石。坚持复盘，自见成效。",
      "generate-habits":
        "根据你的目标，建议从每天25分钟的微习惯开始，不求多但求持续。三周后自然成习惯。",
      "daily-summary":
        "今日朝政已毕。完成日课即是精进，每一日都在为更好的自己奠基。明日再接再厉。",
      "daily-goals": "",
    };
    return NextResponse.json({
      text: fallbacks[type] || "",
      goals: [],
    });
  }
}

