import { useState } from "react";
import { View, Text, Input, Textarea } from "@tarojs/components";
import Taro, { useDidShow } from "@tarojs/taro";
import { apiFetch, getToday } from "../../lib";
import "./index.scss";

export default function ReviewPage() {
  const [form, setForm] = useState({ score: 3, summary: "", highlight: "", lowlight: "", userSupplement: "" });
  const [submitted, setSubmitted] = useState(false);
  const [aiFeedback, setAiFeedback] = useState("");
  const [review, setReview] = useState<any>(null);
  const [aiSummary, setAiSummary] = useState("");
  const [aiSummaryError, setAiSummaryError] = useState(false);
  const [summaryLoading, setSummaryLoading] = useState(true);

  useDidShow(() => {
    const today = getToday();

    // Fetch existing review
    apiFetch(`/api/review?date=${today}`).then((data) => {
      if (data?.id) {
        setReview(data);
        setForm({
          score: data.score,
          summary: data.summary || "",
          highlight: data.highlight || "",
          lowlight: data.lowlight || "",
          userSupplement: data.userSupplement || "",
        });
        setAiFeedback(data.aiFeedback || "");
        setAiSummary(data.aiSummary || "");
        setSubmitted(true);
      }
    }).catch(() => {
      Taro.showToast({ title: "获取复盘数据失败", icon: "none" });
    });

    // Fetch AI daily summary
    setSummaryLoading(true);
    setAiSummaryError(false);
    apiFetch("/api/insights", {
      method: "POST",
      body: JSON.stringify({ type: "daily-summary" }),
    }).then((res) => {
      const text = res?.text || "";
      if (text && text !== "今日尚未打卡，完成日课后自动生成小结。") {
        setAiSummary(text);
      } else {
        setAiSummary(text || "");
      }
      setSummaryLoading(false);
    }).catch(() => {
      setAiSummaryError(true);
      setSummaryLoading(false);
    });
  });

  async function handleSubmit() {
    const today = getToday();
    const data = await apiFetch("/api/review", {
      method: "POST",
      body: JSON.stringify({
        ...form,
        date: today,
        aiSummary: aiSummary || null,
        userSupplement: form.userSupplement || null,
      }),
    });
    setSubmitted(true);
    setReview(data);
    try {
      const ai = await apiFetch("/api/insights", {
        method: "POST",
        body: JSON.stringify({ type: "review", data: form }),
      });
      setAiFeedback(ai.text || "");
    } catch {}
  }

  function renderAiSummaryCard() {
    if (summaryLoading) {
      return (
        <View className="ai-summary-card">
          <View className="ai-summary-header">
            <Text className="ai-summary-icon">🤖</Text>
            <Text className="ai-summary-title">今日小结</Text>
          </View>
          <View className="skeleton-lines">
            <View className="skeleton-line w-80" />
            <View className="skeleton-line w-60" />
            <View className="skeleton-line w-70" />
          </View>
        </View>
      );
    }

    if (aiSummaryError) {
      return (
        <View className="ai-summary-card ai-summary-fallback">
          <View className="ai-summary-header">
            <Text className="ai-summary-icon">🤖</Text>
            <Text className="ai-summary-title">今日小结</Text>
          </View>
          <Text className="ai-summary-fallback-text">今日小结暂不可用</Text>
        </View>
      );
    }

    return (
      <View className="ai-summary-card">
        <View className="ai-summary-header">
          <Text className="ai-summary-icon">🤖</Text>
          <Text className="ai-summary-title">今日小结</Text>
        </View>
        {aiSummary ? (
          <Text className="ai-summary-text">{aiSummary}</Text>
        ) : (
          <Text className="ai-summary-empty-text">
            今日尚未打卡，完成日课后自动生成小结
          </Text>
        )}
        <Textarea
          className="ai-summary-supplement"
          placeholder="在此写下你的补充感悟..."
          value={form.userSupplement}
          onInput={(e) => setForm({ ...form, userSupplement: e.detail.value })}
          maxlength={500}
        />
      </View>
    );
  }

  // ---- Result view ----
  if (review && submitted) {
    return (
      <View className="page">
        <Text className="page-title">每日复盘</Text>

        {renderAiSummaryCard()}

        <View className="review-card center">
          <Text className="review-score">
            {["", "😔", "😐", "🙂", "😊", "🌟"][review.score]}
          </Text>
          <Text className="review-summary">今日评分 {review.score}/5</Text>
          <Text className="review-summary">{review.summary}</Text>
        </View>

        {aiFeedback ? (
          <View className="ai-card">
            <Text className="ai-title">⭐ AI 教练点评</Text>
            <Text className="ai-text">{aiFeedback}</Text>
          </View>
        ) : null}

        <View className="split-cards">
          <View className="split-card">
            <Text className="split-label">今日亮点</Text>
            <Text className="split-text">{review.highlight || "—"}</Text>
          </View>
          <View className="split-card">
            <Text className="split-label">待改进</Text>
            <Text className="split-text">{review.lowlight || "—"}</Text>
          </View>
        </View>
        <View className="submit-btn" onClick={() => setSubmitted(false)}>
          <Text>编辑复盘</Text>
        </View>
      </View>
    );
  }

  // ---- Edit form view ----
  return (
    <View className="page">
      <Text className="page-title">每日复盘</Text>
      <Text className="page-subtitle">三省吾身，日日精进</Text>

      {renderAiSummaryCard()}

      <View className="review-card">
        <View className="form-group">
          <Text className="form-label">今日整体评分</Text>
          <View className="stars">
            {[1, 2, 3, 4, 5].map((s) => (
              <Text key={s} className={`star ${form.score >= s ? "active" : ""}`} onClick={() => setForm({ ...form, score: s })}>⭐</Text>
            ))}
          </View>
        </View>

        <View className="form-group">
          <Text className="form-label">一句话总结</Text>
          <Input className="form-input" placeholder="今天过得怎么样？" value={form.summary} onInput={(e) => setForm({ ...form, summary: e.detail.value })} />
        </View>

        <View className="form-group">
          <Text className="form-label">今日亮点</Text>
          <Textarea className="form-textarea" placeholder="最值得骄傲的事" value={form.highlight} onInput={(e) => setForm({ ...form, highlight: e.detail.value })} maxlength={500} />
        </View>

        <View className="form-group">
          <Text className="form-label">需要改进</Text>
          <Textarea className="form-textarea" placeholder="可以做得更好的地方" value={form.lowlight} onInput={(e) => setForm({ ...form, lowlight: e.detail.value })} maxlength={500} />
        </View>

        <View className="submit-btn" onClick={handleSubmit}><Text>提交复盘</Text></View>
      </View>
    </View>
  );
}

