import { useState, useEffect } from "react";
import { View, Text } from "@tarojs/components";
import Taro, { useDidShow } from "@tarojs/taro";
import { apiFetch, getToday, formatDate, getDomains } from "../../lib";
import "./index.scss";

interface Habit {
  id: string;
  title: string;
  description: string | null;
  domainId: string;
  unit: string;
  targetValue: number;
  isActive: boolean;
  logs?: { date: string; completed: boolean; value: number }[];
}

interface DailyGoal {
  title: string;
  detail: string;
  reason: string;
}

export default function IndexPage() {
  const [habits, setHabits] = useState<Habit[]>([]);
  const [loading, setLoading] = useState(true);
  const [dailyGoals, setDailyGoals] = useState<DailyGoal[]>([]);
  const [goalsLoading, setGoalsLoading] = useState(false);
  const [goalsExpanded, setGoalsExpanded] = useState<Set<number>>(new Set());
  const [goalsDismissed, setGoalsDismissed] = useState(false);

  useDidShow(() => {
    fetchHabits();
    checkDismissed();
    fetchDailyGoals();
  });

  function checkDismissed() {
    const dismissedDate = Taro.getStorageSync("goals_dismissed_date");
    setGoalsDismissed(dismissedDate === getToday());
  }

  async function fetchHabits() {
    try {
      const data = await apiFetch("/api/habits?date=" + getToday());
      setHabits(data);
    } catch {
      Taro.showToast({ title: "获取今日习惯失败", icon: "none" });
    }
    setLoading(false);
  }

  async function fetchDailyGoals() {
    setGoalsLoading(true);
    try {
      const data = await apiFetch("/api/insights", {
        method: "POST",
        body: JSON.stringify({ type: "daily-goals" }),
      });
      setDailyGoals(data?.goals || []);
    } catch {
      setDailyGoals([]);
    }
    setGoalsLoading(false);
  }

  async function toggleHabit(habitId: string) {
    try {
      await apiFetch("/api/logs", {
        method: "POST",
        body: JSON.stringify({ habitId, date: getToday() }),
      });
      fetchHabits();
    } catch {
      Taro.showToast({ title: "打卡失败", icon: "none" });
    }
  }

  function toggleGoalExpand(idx: number) {
    setGoalsExpanded((prev) => {
      const next = new Set(prev);
      if (next.has(idx)) {
        next.delete(idx);
      } else {
        next.add(idx);
      }
      return next;
    });
  }

  function dismissGoals() {
    Taro.setStorageSync("goals_dismissed_date", getToday());
    setGoalsDismissed(true);
  }

  const completedCount = habits.filter(
    (h) => h.logs?.length && h.logs[0]?.completed
  ).length;
  const totalCount = habits.filter((h) => h.isActive).length;
  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;

  function renderGoalsBlock() {
    if (goalsDismissed) return null;
    if (goalsLoading) {
      return (
        <View className="goals-card">
          <View className="goals-header">
            <Text className="goals-title">📋 今日建议目标</Text>
          </View>
          <View className="skeleton-lines">
            <View className="skeleton-line w-80" />
            <View className="skeleton-line w-60" />
          </View>
        </View>
      );
    }
    if (!dailyGoals || dailyGoals.length === 0) return null;

    return (
      <View className="goals-card">
        <View className="goals-header">
          <Text className="goals-title">📋 今日建议目标</Text>
          <View className="goals-dismiss" onClick={dismissGoals}>
            <Text>✕</Text>
          </View>
        </View>
        {dailyGoals.map((goal, idx) => {
          const expanded = goalsExpanded.has(idx);
          return (
            <View
              key={idx}
              className={`goals-item ${expanded ? "expanded" : ""}`}
              onClick={() => toggleGoalExpand(idx)}
            >
              <View className="goals-item-header">
                <Text className="goals-item-title">{goal.title}</Text>
                <Text className="goals-item-arrow">{expanded ? "▲" : "▼"}</Text>
              </View>
              {expanded && (
                <View className="goals-item-body">
                  <Text className="goals-item-detail">{goal.detail}</Text>
                  <Text className="goals-item-reason">理由：{goal.reason}</Text>
                </View>
              )}
            </View>
          );
        })}
      </View>
    );
  }

  return (
    <View className="page">
      <Text className="header-date">{formatDate(new Date())}</Text>
      <Text className="header-title">今日日课</Text>

      {renderGoalsBlock()}

      <View className="progress-card">
        <View className="progress-ring">
          <View style={{
            width: "140rpx", height: "140rpx", borderRadius: "50%",
            background: `conic-gradient(#c4843e ${progressPct * 3.6}deg, #332e28 0deg)`,
            display: "flex", alignItems: "center", justifyContent: "center"
          }}>
            <View style={{
              width: "110rpx", height: "110rpx", borderRadius: "50%",
              background: "#221e1a", display: "flex", alignItems: "center", justifyContent: "center"
            }}>
              <Text className="progress-pct">{progressPct}%</Text>
            </View>
          </View>
        </View>
        <View className="progress-info">
          <Text className="progress-num">{completedCount}/{totalCount}</Text>
          <Text className="progress-label">今日已完成</Text>
        </View>
      </View>

      {getDomains().map((domain) => {
        const domainHabits = habits.filter((h) => h.domainId === domain.name && h.isActive);
        if (domainHabits.length === 0) return null;
        return (
          <View key={domain.name}>
            <Text className="domain-title">{domain.icon} {domain.name}</Text>
            {domainHabits.map((habit) => {
              const done = !!(habit.logs?.length && habit.logs[0]?.completed);
              return (
                <View
                  key={habit.id}
                  className={`habit-item ${done ? "done" : ""}`}
                  onClick={() => toggleHabit(habit.id)}
                >
                  <View className={`check-icon ${done ? "checked" : ""}`}>
                    {done && <Text>✓</Text>}
                  </View>
                  <View className="habit-text">
                    <Text className={`habit-name ${done ? "done" : ""}`}>{habit.title}</Text>
                    {habit.description && <Text className="habit-desc">{habit.description}</Text>}
                  </View>
                  <Text className="habit-unit">{habit.targetValue}{habit.unit}</Text>
                </View>
              );
            })}
          </View>
        );
      })}

      {totalCount === 0 && (
        <View className="empty">
          <Text>还没有习惯</Text>
          <Text>去「习惯」页面添加吧</Text>
        </View>
      )}
    </View>
  );
}

