/* ============================================
   今日建议目标卡片
   ============================================ */

.goals-card {
  background: linear-gradient(135deg, #1e1a15 0%, #221e1a 100%);
  border: 1rpx solid var(--color-border);
  border-left: 6rpx solid var(--color-accent);
  border-radius: var(--radius-lg);
  padding: var(--space-lg);
  margin-top: var(--space-lg);
  position: relative;
  overflow: hidden;
}

.goals-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 6rpx;
  right: 0;
  height: 1rpx;
  background: linear-gradient(90deg, var(--color-accent-subtle), transparent);
}

.goals-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--space-md);
}

.goals-title {
  font-size: var(--text-md);
  font-weight: 600;
  color: var(--color-accent-light);
  letter-spacing: 0.03em;
}

.goals-dismiss {
  width: 44rpx;
  height: 44rpx;
  border-radius: var(--radius-full);
  background: var(--color-surface);
  border: 1rpx solid var(--color-border);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.2s;
}

.goals-dismiss:active {
  background: var(--color-card-hover);
}

.goals-dismiss Text {
  font-size: 22rpx;
  color: var(--color-text-muted);
  line-height: 1;
}

/* ---- 目标条目 ---- */
.goals-item {
  background: var(--color-card);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-md);
  margin-bottom: var(--space-sm);
  overflow: hidden;
  transition: border-color 0.2s;
}

.goals-item:active {
  border-color: var(--color-accent-subtle);
}

.goals-item-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-md);
  cursor: pointer;
}

.goals-item-title {
  font-size: var(--text-sm);
  font-weight: 500;
  color: var(--color-text-primary);
  letter-spacing: 0.02em;
}

.goals-item-arrow {
  font-size: 20rpx;
  color: var(--color-text-muted);
  transition: transform 0.2s ease;
}

.goals-item-body {
  padding: 0 var(--space-md) var(--space-md);
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  animation: goals-expand 0.25s ease-out;
}

@keyframes goals-expand {
  from {
    opacity: 0;
    max-height: 0;
    transform: translateY(-8rpx);
  }
  to {
    opacity: 1;
    max-height: 300rpx;
    transform: translateY(0);
  }
}

.goals-item-detail {
  display: block;
  font-size: var(--text-xs);
  color: var(--color-text-secondary);
  line-height: 1.7;
}

.goals-item-reason {
  display: block;
  font-size: var(--text-xs);
  color: var(--color-accent-light);
  line-height: 1.6;
  opacity: 0.85;
}

/* ---- 骨架屏 ---- */
.skeleton-lines {
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
  padding: var(--space-sm) 0;
}

.skeleton-line {
  height: 24rpx;
  border-radius: 12rpx;
  background: linear-gradient(
    90deg,
    var(--color-border) 25%,
    var(--color-border-light) 50%,
    var(--color-border) 75%
  );
  background-size: 200% 100%;
  animation: skeleton-shimmer 1.5s ease-in-out infinite;
}

.skeleton-line.w-80 {
  width: 80%;
}

.skeleton-line.w-60 {
  width: 60%;
}

@keyframes skeleton-shimmer {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

